\section{H${}^0$ Hom finiteness carrier predicate (iter-041)}
\label{sec:IsAffineHModuleHomFinite_iter041}

Iter-040 packaged the H${}^{>0}$ side of the affine-corner input as a class. Iter-041 supplies the parallel H${}^0$ side: a class-style predicate stating that for every affine open $U$ of $C.\mathtt{left}$, the morphism group $((\mathtt{presheafToSheaf}\,J\,(\ModuleCat\,k)).\mathtt{obj}\,((\mathtt{yoneda} \circ \mathtt{free}\,k).\mathtt{obj}\,U) \to F)$ is $\Module.\mathrm{Finite}$ over $k$ — morally, $\Gamma(U, F)$ is a finite $k$-module on each affine corner. Together with iter-040's H${}^{>0}$ vanishing class, this packages the *full* affine-corner input the LES finite-length transport (queued for iter-043+) consumes.

\begin{theorem}\leanok
[H${}^0$ Hom finiteness carrier predicate]
  \label{thm:Scheme_IsAffineHModuleHomFinite}
  \lean{AlgebraicGeometry.Scheme.IsAffineHModuleHomFinite}
  \uses{def:Scheme_HModule_prime}
  Let $k$ be a field, $C : \Over\,(\Spec\,(\CommRingCat.\mathrm{of}\,k))$, and $F$ a sheaf of $\ModuleCat\,k$ on $\Opens\,(C.\mathtt{left}.\toTopCat)$. The class \lstinline{IsAffineHModuleHomFinite k C F} bundles the proposition that for every affine open $U$ of $C.\mathtt{left}$, the morphism group $(\mathtt{presheafToSheaf}\,J\,(\ModuleCat\,k)).\mathtt{obj}\,((\mathtt{yoneda} \circ \mathtt{free}\,k).\mathtt{obj}\,U) \to F$ is $\Module.\mathrm{Finite}$ over $k$.
\end{theorem}

\begin{proof}
  \leanok
  Definitional: a \texttt{class} with a single field \lstinline{module_finite_hom : \forall \{U\}, IsAffineOpen U \to Module.Finite k ((presheafToSheaf _ _).obj ((yoneda \circ free k).obj U) \to F)}. The Hom-side analogue of iter-040's H${}^{>0}$ class. Mirrors the typeclass-style hypothesis already used at iter-038/039 call sites, lifted to a class-style affine quantifier so that consumers can range over every affine open of $C.\mathtt{left}$ uniformly (rather than supplying one $\lstinline{[Module.Finite k (Hom)]}$ instance per call site).
\end{proof}

\begin{theorem}\leanok
[$\Module\,k$-finite consumer of H${}^0$ Hom finiteness]
  \label{thm:Scheme_module_finite_HModule_prime_zero_of_isAffineHModuleHomFinite}
  \lean{AlgebraicGeometry.Scheme.module_finite_HModule'_zero_of_isAffineHModuleHomFinite}
  \uses{thm:Scheme_IsAffineHModuleHomFinite, thm:Scheme_module_finite_HModule_prime_zero}
  Let $k$, $C$, $F$ be as in Theorem~\ref{thm:Scheme_IsAffineHModuleHomFinite}, and assume \lstinline{IsAffineHModuleHomFinite k C F}. For any affine open $U$ of $C.\mathtt{left}$, the cohomology group $\HModulePrime\,k\,F\,0\,U$ is $\Module.\mathrm{Finite}$ over $k$.
\end{theorem}

\begin{proof}
  \uses{thm:Scheme_IsAffineHModuleHomFinite, thm:Scheme_module_finite_HModule_prime_zero}
  \leanok
  Apply the class field to extract \lstinline{Module.Finite k ((presheafToSheaf _ _).obj _ \to F)}, then chain through iter-038's \lstinline{Scheme.module_finite_HModule'_zero} which transports $\Module.\mathrm{Finite}$-ness across iter-015's H${}^0$ algebraic bridge $\HModulePrime\,k\,F\,0\,U \simeq_{\Linear k} ((\mathtt{presheafToSheaf}\,J\,(\ModuleCat\,k)).\mathtt{obj}\,((\mathtt{yoneda} \circ \mathtt{free}\,k).\mathtt{obj}\,U) \to F)$. Combined body: \lstinline{have : Module.Finite k _ := IsAffineHModuleHomFinite.module_finite_hom hU; Scheme.module_finite_HModule'_zero k F U}.
\end{proof}

\begin{remark}[Use in the cover-evaluation chain, completed]
  After iter-041 the cover-evaluation chain consumes both class-style affine inputs uniformly: for an \lstinline{AffineCoverMVSquare} $S$ with corners $X_1, X_2, X_3$ affine and $X_4 = \top$, given \lstinline{IsAffineHModuleHomFinite k C F} and \lstinline{IsAffineHModuleVanishing k C F},
  \begin{enumerate}
    \item $\HModulePrime^0(X_j)$ is $\Module\,k$-finite for $j = 1, 2, 3$ via Theorem~\ref{thm:Scheme_module_finite_HModule_prime_zero_of_isAffineHModuleHomFinite} (iter-041) — one class lookup per affine corner, no per-corner Hom-finiteness hypothesis at the call site.
    \item $\HModulePrime^i(X_j) \simeq 0$ for $j = 1, 2, 3$ and $i > 0$ via Theorem~\ref{thm:Scheme_module_finite_HModule_prime_of_isAffineHModuleVanishing} (iter-040).
    \item The iter-029/030 LES then forces $\HModulePrime^1(X_4)$ to be a cokernel of a $\Module\,k$-finite map, hence $\Module\,k$-finite (queued for iter-043+ — bridges $\AddCommGrpCat$-side exactness to $k$-linear \lstinline{Function.Exact}).
    \item The iter-035 corner-bridge identifies $\HModulePrime^1(X_4)$ with $\HModule\,k\,F\,1$, and iter-037's transport carries the finiteness across — landing $\Module.\mathrm{Finite}\,k\,(\HModule\,k\,(\toModuleKSheaf\,C)\,1)$, the genus carrier (Definition~\ref{def:genus}).
  \end{enumerate}
  Iter-042+ produces the carrier instances \lstinline{IsAffineHModuleHomFinite k C (toModuleKSheaf C)} (via Stein-factorization-derived $\Gamma(\Spec A, \struct C) \simeq A$ on affine corners of a finite-type $k$-scheme) and \lstinline{IsAffineHModuleVanishing k C (toModuleKSheaf C)} (via project-local Čech-vs-derived comparison + affine Čech vanishing).
\end{remark}

\section{Use in the project}
